153	  private async pollForImageUrl(
154	    generationId: string,
155	    headers: Record<string, string | undefined>,
156	    abortSignal: AbortSignal | undefined,
157	    pollSettings?: { pollIntervalMillis?: number; maxPollAttempts?: number },
158	  ): Promise<string> {
159	    const url = this.getLumaGenerationsUrl(generationId);
160	    const maxPollAttempts =
161	      pollSettings?.maxPollAttempts ?? this.maxPollAttempts;
162	    const pollIntervalMillis =
163	      pollSettings?.pollIntervalMillis ?? this.pollIntervalMillis;
164	
165	    for (let i = 0; i < maxPollAttempts; i++) {
166	      const { value: statusResponse } = await getFromApi({
167	        url,
168	        headers,
169	        abortSignal,
170	        fetch: this.config.fetch,
171	        failedResponseHandler: this.createLumaErrorHandler(),
172	        successfulResponseHandler: createJsonResponseHandler(
173	          lumaGenerationResponseSchema,
174	        ),
175	      });
176	
177	      switch (statusResponse.state) {
178	        case 'completed':
179	          if (!statusResponse.assets?.image) {
180	            throw new InvalidResponseDataError({
181	              data: statusResponse,
182	              message: `Image generation completed but no image was found.`,
183	            });
184	          }
185	          return statusResponse.assets.image;
186	        case 'failed':
187	          throw new InvalidResponseDataError({
188	            data: statusResponse,
189	            message: `Image generation failed.`,
190	          });
191	      }
192	      await delay(pollIntervalMillis);
193	    }
