401	         */
402	        images: z
403	          .array(
404	            z.object({
405	              /**
406	               * The weight of this image's influence on the generation.
407	               * - For `image`: Higher weight = closer to reference (default: 0.85)
408	               * - For `style`: Higher weight = stronger style influence (default: 0.8)
409	               * - For `modify_image`: Higher weight = closer to input, lower = more creative (default: 1.0)
410	               */
411	              weight: z.number().min(0).max(1).nullish(),
412	
413	              /**
414	               * The identity name for character references.
415	               * Used with `character` to specify which identity group the image belongs to.
