### 4. **Provider Factory Pattern** (`luma-provider.ts`)

```typescript
export interface LumaProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface LumaProvider extends ProviderV3 {
  image(modelId: LumaImageModelId): ImageModelV3;
  imageModel(modelId: LumaImageModelId): ImageModelV3;
}

export function createLuma(options: LumaProviderSettings = {}): LumaProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () => ({
    Authorization: `Bearer ${loadApiKey({ apiKey: options.apiKey })}`,
    ...options.headers,
  });

  const createImageModel = (modelId: LumaImageModelId) =>
    new LumaImageModel(modelId, {
      provider: 'luma.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3',
    image: createImageModel,
    imageModel: createImageModel,
    languageModel: () => throw NoSuchModelError(),
    embeddingModel: () => throw NoSuchModelError(),
  };
}

export const luma = createLuma();
```

**Factory pattern key points:**
- `createXxx()` function takes optional settings
- Settings include API key, base URL, custom headers, custom fetch
- Default instance exported for zero-config usage
- Implements `ProviderV3` interface
- Returns object with model creation methods
- Throws errors for unsupported model types

