import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'This model does not support the `aspectRatio` option. Use `size` instead.',
      });
    }

    // Parse and validate provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generations`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        n,
        ...(size != null ? { size } : {}),
        ...(seed != null ? { seed } : {}),
        ...(pixelArtOptions?.style != null
          ? { style: pixelArtOptions.style }
          : {}),
        ...(pixelArtOptions?.pixelDensity != null
          ? { pixel_density: pixelArtOptions.pixelDensity }
          : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (error: PixelArtErrorData) => error.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
    });

    const images = response.data.map(item =>
      convertBase64ToUint8Array(item.b64_json),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// limited version of the schema, focussed on what is needed for the implementation
// this approach limits breakages when the API changes and increases efficiency
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.string().nullish(),
  }),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 *
 * @see https://api.pixelart.ai/v1/docs
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The pixel art rendering style to apply during generation.
         *
         * - `pixel`: Classic pixel art style with sharp edges and limited color palette.
         * - `retro`: Retro 80s/90s inspired pixel art with dithering effects.
         * - `8bit`: 8-bit video game style pixel art with chunky pixels.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The pixel density (pixels per block). Controls how blocky the result appears.
         *
         * Higher values produce more pixelated output with larger, more visible blocks.
         * Lower values produce smoother output with finer pixel detail.
         *
         * Range: 1–64. Default: 8.
         */
        pixelDensity: z.number().min(1).max(64).nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

