import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A pixel art hero in a fantasy dungeon';

// Base64 encoding of 'test-image-content'
const TEST_BASE64_IMAGE = Buffer.from('test-image-content').toString('base64');

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('test-model', {
    provider: 'pixelart',
    baseURL: 'https://api.example.com',
    headers: headers ?? (() => ({ 'api-key': 'test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/images/generations': {
      response: {
        type: 'json-value',
        body: {
          created: 1704067200,
          data: [{ b64_json: TEST_BASE64_IMAGE }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('should call the correct URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/images/generations',
      );
    });

    it('should pass the correct parameters in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 2,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 2,
        size: '512x512',
        seed: 42,
      });
    });

    it('should omit size and seed from request body when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toStrictEqual({ prompt, n: 1 });
      expect(body).not.toHaveProperty('size');
      expect(body).not.toHaveProperty('seed');
    });

    it('should pass style provider option as style in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { style: 'retro' } },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        style: 'retro',
      });
    });

    it('should pass pixelDensity provider option as pixel_density in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: { pixelart: { pixelDensity: 16 } },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        pixel_density: 16,
      });
    });

    it('should pass both style and pixelDensity together', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit', pixelDensity: 32 },
        },
        files: undefined,
        mask: undefined,
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        n: 1,
        size: '256x256',
        style: '8bit',
        pixel_density: 32,
      });
    });

    it('should pass custom request headers', async () => {
      const modelWithHeaders = createBasicModel({
        headers: () => ({
          'Custom-Provider-Header': 'provider-header-value',
        }),
      });

      await modelWithHeaders.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'Custom-Request-Header': 'request-header-value',
        },
        files: undefined,
        mask: undefined,
      });

      expect(server.calls[0].requestHeaders).toStrictEqual({
        'content-type': 'application/json',
        'custom-provider-header': 'provider-header-value',
        'custom-request-header': 'request-header-value',
      });
    });

    it('should return images as Uint8Array converted from base64', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        files: undefined,
        mask: undefined,
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      expect(result.images[0]).toEqual(
        new TextEncoder().encode('test-image-content'),
      );
    });

    it('should handle API errors', async () => {
      server.urls['https://api.example.com/images/generations'].response = {
        type: 'json-value',
        status: 400,
        body: {
          error: {
            message: 'Invalid request: prompt is required',
            code: 'invalid_request',
          },
        },
      };

      const model = createBasicModel();
      await expect(
        model.doGenerate({
          prompt: '',
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        }),
      ).rejects.toMatchObject({
        message: expect.stringContaining('Invalid request'),
        statusCode: 400,
      });
    });

    describe('warnings', () => {
      it('should emit unsupported warning for aspectRatio', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: '16:9',
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.warnings).toMatchInlineSnapshot(`
          [
            {
              "details": "This model does not support the \`aspectRatio\` option. Use \`size\` instead.",
              "feature": "aspectRatio",
              "type": "unsupported",
            },
          ]
        `);
      });

      it('should not emit warnings when only supported parameters are used', async () => {
        const model = createBasicModel();

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: '1024x1024',
          aspectRatio: undefined,
          seed: 123,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.warnings).toStrictEqual([]);
      });
    });

    describe('response metadata', () => {
      it('should include timestamp, headers, and modelId in response', async () => {
        const testDate = new Date('2024-01-01T00:00:00Z');
        const model = createBasicModel({
          currentDate: () => testDate,
        });

        const result = await model.doGenerate({
          prompt,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
          files: undefined,
          mask: undefined,
        });

        expect(result.response).toStrictEqual({
          timestamp: testDate,
          modelId: 'test-model',
          headers: expect.any(Object),
        });
      });
    });
  });

  describe('constructor', () => {
    it('should expose correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart');
      expect(model.modelId).toBe('test-model');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(4);
    });
  });
});

